51b63988-3e2e-4aea-a85c-6aac27fecdee	authentik default Active Directory Mapping: sAMAccountName	return {\n    "username": ldap.get("sAMAccountName"),\n}	goauthentik.io/sources/ldap/ms-samaccountname
e7918468-34f3-438e-90d4-46942c20e108	authentik default Active Directory Mapping: userPrincipalName	return {\n    "attributes": {\n        "upn": list_flatten(ldap.get("userPrincipalName")),\n    },\n}	goauthentik.io/sources/ldap/ms-userprincipalname
b3cc4b30-612f-4d82-9112-c36514241eae	authentik default Active Directory Mapping: givenName	return {\n    "attributes": {\n        "givenName": list_flatten(ldap.get("givenName")),\n    },\n}	goauthentik.io/sources/ldap/ms-givenName
d60e8b3a-3e5c-408e-a5f9-20e132451529	authentik default Active Directory Mapping: sn	return {\n    "attributes": {\n        "sn": list_flatten(ldap.get("sn")),\n    },\n}	goauthentik.io/sources/ldap/ms-sn
f1e396f3-1f47-46cc-8f14-d1d669e448fa	authentik default OpenLDAP Mapping: uid	return {\n    "username": ldap.get("uid"),\n}	goauthentik.io/sources/ldap/openldap-uid
c0bc21cf-af44-4edc-bee8-0d57798477d2	authentik default OpenLDAP Mapping: cn	return {\n    "name": ldap.get("cn"),\n}	goauthentik.io/sources/ldap/openldap-cn
7e9dcef3-8a50-4a3d-a879-2ef9aa203918	authentik default SCIM Mapping: Group	return {\n    "displayName": group.name,\n}	goauthentik.io/providers/scim/group
14a26102-f6cc-47cf-9428-bb7d8f597046	authentik default SCIM Mapping: User	# Some implementations require givenName and familyName to be set\ngivenName, familyName = request.user.name, " "\nformatted = request.user.name + " "\n# This default sets givenName to the name before the first space\n# and the remainder as family name\n# if the user's name has no space the givenName is the entire name\n# (this might cause issues with some SCIM implementations)\nif " " in request.user.name:\n    givenName, _, familyName = request.user.name.partition(" ")\n    formatted = request.user.name\n\n# photos supports URLs to images, however authentik might return data URIs\navatar = request.user.avatar\nphotos = None\nif "://" in avatar:\n    photos = [{"value": avatar, "type": "photo"}]\n\nlocale = request.user.locale()\nif locale == "":\n    locale = None\n\nemails = []\nif request.user.email != "":\n    emails = [{\n        "value": request.user.email,\n        "type": "other",\n        "primary": True,\n    }]\nreturn {\n    "userName": request.user.username,\n    "name": {\n        "formatted": formatted,\n        "givenName": givenName,\n        "familyName": familyName,\n    },\n    "displayName": request.user.name,\n    "photos": photos,\n    "locale": locale,\n    "active": request.user.is_active,\n    "emails": emails,\n}	goauthentik.io/providers/scim/user
c95b7d80-f047-445c-90fa-1f4cc370664a	authentik default Google Workspace Mapping: User	# Field reference:\n# https://developers.google.com/admin-sdk/directory/reference/rest/v1/users#User\n# Google require givenName and familyName to be set\ngivenName, familyName = request.user.name, " "\nformatted = request.user.name + " "\n# This default sets givenName to the name before the first space\n# and the remainder as family name\n# if the user's name has no space the givenName is the entire name\nif " " in request.user.name:\n    givenName, _, familyName = request.user.name.partition(" ")\n    formatted = request.user.name\nuser = {\n    "name": {\n        "fullName": formatted,\n        "familyName": familyName.strip(),\n        "givenName": givenName.strip(),\n        "displayName": formatted,\n    },\n    "suspended": not request.user.is_active,\n}\nif not connection:\n    user["password"] = request.user.password\nreturn user	goauthentik.io/providers/google_workspace/user
72641d79-4575-4623-8954-5a6225c1e7a5	authentik default Google Workspace Mapping: Group	# Field reference:\n# https://developers.google.com/admin-sdk/directory/reference/rest/v1/groups#Group\nreturn {\n    "name": group.name,\n}	goauthentik.io/providers/google_workspace/group
b1e3aebf-93d4-4652-9487-0b41d8cec630	authentik default OAuth Mapping: Application Entitlements	entitlements = [entitlement.name for entitlement in request.user.app_entitlements(provider.application)]\nreturn {\n    "entitlements": entitlements,\n    "roles": entitlements,\n}	goauthentik.io/providers/oauth2/scope-entitlements
50a999ad-cf3e-4b50-9918-5d827b8124a6	authentik default OAuth Mapping: OpenID 'offline_access'	# This scope grants the application a refresh token that can be used to refresh user data\n# and let the application access authentik without the users interaction\nreturn {}	goauthentik.io/providers/oauth2/scope-offline_access
117c4b10-a201-46a6-bfdc-b1496a67e88e	authentik default OAuth Mapping: authentik API access	# This scope grants the application the ability to access the authentik API\n# on behalf of the authorizing user\nreturn {}	goauthentik.io/providers/oauth2/scope-authentik_api
0e663bc0-f053-4378-a684-6e966d4a2424	authentik default OAuth Mapping: OpenID 'openid'	# This scope is required by the OpenID-spec, and must as such exist in authentik.\n# The scope by itself does not grant any information\nreturn {}	goauthentik.io/providers/oauth2/scope-openid
6ece7c23-bed8-4563-a938-476381c3fb1f	authentik default OAuth Mapping: OpenID 'email'	return {\n    "email": request.user.email,\n    "email_verified": True\n}	goauthentik.io/providers/oauth2/scope-email
